/** UsptRsltHistDao.insert */
insert into uspt_rslt_hist
	(
		rslt_hist_id
		, rslt_id
		, rslt_sttus_cd
		, presentn_dt
		, attachment_group_id
		, process_cn
		, process_mber_type
		, creator_id
		, created_dt
	) values (
		#{rsltHistId}
		, #{rsltId}
		, #{rsltSttusCd}
		, #{presentnDt}
		, #{attachmentGroupId}
		, #{processCn}
		, #{processMberType}
		, #{creatorId}
		, #{createdDt}
	)

mapper.select:
/** UsptRsltHistDao.selectList */ select urh.rslt_hist_id , urh.rslt_id , urh.rslt_sttus_cd , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@REPRT_CODE_GROUP}', urh.rslt_sttus_cd) as rslt_sttus , urh.presentn_dt , urh.attachment_group_id , urh.process_cn , urh.process_mber_type , urh.creator_id , urh.created_dt , ci.member_nm as opetr_nm , ci.login_id from uspt_rslt_hist urh left outer join cmmt_insider ci on ci.member_id = urh.creator_id where urh.rslt_id = #{rsltId}
and urh.process_mber_type = #{processMberType}
order by urh.created_dt desc
